1	const NEIGHBOR_OFFSETS: [number, number][] = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [ 0, -1],          [ 0, 1],
4	  [ 1, -1], [ 1, 0], [ 1, 1],
5	];
6	
7	export function nextGeneration(grid: boolean[][]): boolean[][] {
8	  if (grid.length === 0) return [];
9	
10	  const rows = grid.length;
11	  const cols = grid[0].length;
12	
13	  const isInBounds = (r: number, c: number): boolean =>
14	    r >= 0 && r < rows && c >= 0 && c < cols;
15	
16	  const countNeighbors = (r: number, c: number): number =>
17	    NEIGHBOR_OFFSETS.filter(([dr, dc]) => {
18	      const nr = r + dr;
19	      const nc = c + dc;
20	      return isInBounds(nr, nc) && grid[nr][nc];
21	    }).length;
22	
23	  const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
24	  const spawns = (neighbors: number): boolean => neighbors === 3;
25	
26	  const nextGrid = grid.map((row, r) =>
27	    row.map((cell, c) => {
28	      const neighbors = countNeighbors(r, c);
29	      return cell ? survives(neighbors) : spawns(neighbors);
30	    })
31	  );
32	
33	  const hasLiveCell = nextGrid.some(row => row.some(cell => cell));
34	  return hasLiveCell ? nextGrid : [];
35	}
